package com.chaobo.scm.supplier.interfaces.web;
import com.chaobo.scm.common.api.ApiResponse;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.order.*;import com.chaobo.scm.supplier.application.shared.CommandResult;import jakarta.servlet.http.HttpServletRequest;import jakarta.validation.Valid;import jakarta.validation.constraints.*;import org.springframework.web.bind.annotation.*;import java.math.BigDecimal;import java.time.*;import java.util.List;
@RestController @RequestMapping("/openapi/supplier/v1/purchase-orders")public class PurchaseOrderOpenApiController{private final PurchaseOrderEventConsumerApplicationService consumer;public PurchaseOrderOpenApiController(PurchaseOrderEventConsumerApplicationService consumer){this.consumer=consumer;}@PostMapping public ApiResponse<CommandResult> receive(@Valid @RequestBody ReceiveRequest body,HttpServletRequest request){source(request);return ok(consumer.consume(event(request,"PurchaseOrderReleased",body.purchaseOrderId(),body.purchaseOrderNo(),body.supplierId(),body.confirmDeadline(),body.lines(),body.sourceVersion(),null)),request);}@PostMapping("/events")public ApiResponse<CommandResult> consume(@Valid @RequestBody EventRequest body,HttpServletRequest request){source(request);return ok(consumer.consume(event(request,body.eventType(),body.purchaseOrderId(),body.purchaseOrderNo(),body.supplierId(),body.confirmDeadline(),body.lines(),body.sourceVersion(),body.reason())),request);}private PurchaseOrderEvent event(HttpServletRequest request,String type,long id,String no,long supplierId,OffsetDateTime deadline,List<SourceLine> lines,int version,String reason){return new PurchaseOrderEvent(request.getHeader("X-Event-Code"),type,id,no,supplierId,deadline,lines==null?List.of():lines.stream().map(line->new PurchaseOrderEvent.Line(line.skuCode(),line.orderQty(),line.requestedDeliveryDate())).toList(),version,reason);}private void source(HttpServletRequest request){if(!"PURCHASE".equals(request.getHeader("X-Source-System")))throw new BusinessException(ErrorCode.FORBIDDEN,"来源系统必须是PURCHASE");if(request.getHeader("X-Event-Code")==null)throw new BusinessException(ErrorCode.VALIDATION_FAILED,"缺少X-Event-Code");}private ApiResponse<CommandResult> ok(CommandResult result,HttpServletRequest request){return ApiResponse.success(result,request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}public record ReceiveRequest(@Positive long purchaseOrderId,@NotBlank String purchaseOrderNo,@Positive long supplierId,OffsetDateTime confirmDeadline,@NotEmpty List<@Valid SourceLine>lines,@Positive int sourceVersion){}public record EventRequest(@NotBlank String eventType,@Positive long purchaseOrderId,String purchaseOrderNo,long supplierId,OffsetDateTime confirmDeadline,List<@Valid SourceLine>lines,@Positive int sourceVersion,String reason){}public record SourceLine(@NotBlank String skuCode,@NotNull @Positive BigDecimal orderQty,LocalDate requestedDeliveryDate){} }
